UPDATE public.questions SET category = 'Arrays', description = 'Given an array of integers nums and an integer target, return indices of the two numbers such that they add up to target. Reads input as a JSON array: [nums, target]. Return the two indices as an array.', starter_code = 'function twoSum(nums, target) {
  const seen = new Map();
  for (let i = 0; i < nums.length; i++) {
    const need = target - nums[i];
    if (seen.has(need)) return [seen.get(need), i];
    seen.set(nums[i], i);
  }
  return [];
}

