i) == ''\\\\'') { i++; out.append(s.charAt(i)); } else out.append(s.charAt(i)); i++; }\n    i++; v.str = out.toString(); return v;\n  }\n  JsonValue parseBool() {\n    JsonValue v = new JsonValue(); v.type = JsonValue.Type.BOOL;\n    if (s.charAt(i) == ''t'') { v.bool = true; i += 4; } else { v.bool = false; i += 5; }\n    return v;\n  }\n  JsonValue parseNumber() {\n    JsonValue v = new JsonValue(); v.type = JsonValue.Type.NUM; int start = i;\n    while (i < s.length() && (Character.isDigit(s.charAt(i)) || \"-+.eE\".indexOf(s.charAt(i)) >= 0)) i++;\n    v.num = Double.parseDouble(s.substring(start, i)); return v;\n  }\n}\n\nclass JsonOut {\n  static String of(int v) { return String.valueOf(v); }\n  static String of(boolean v) { return v ? \"true\" : \"false\"; }\n  static String of(String v) { return \"\\\"\" + v + \"\\\"\"; }\n  static String of(int[] v) {\n    StringBuilder out = new StringBuilder(\"[\");\n    for (int k = 0; k < v.length; k++) { if (k > 0) out.append(\",\"); out.append(v[k]); }\n    return out.append(\"]\").toString();\n  }\n  static String of(int[][] v) {\n    StringBuilder out = new StringBuilder(\"[\");\n    for (int k = 0; k < v.length; k++) { if (k > 0) out.append(\",\"); out.append(of(v[k])); }\n    return out.append(\"]\").toString();\n  }\n}\n\npublic class Main {\n  public static void main(String[] args) throws IOException {\n    StringBuilder sb = new StringBuilder();\n    BufferedReader br = new BufferedReader(new InputStreamReader(System.in));\n    String line; while ((line = br.readLine()) != null) sb.append(line);\n    JsonValue input = new JsonParser(sb.toString()).parse();\n    int[] nums = input.arr.get(0).asIntArray();\n    int target = input.arr.get(1).asInt();\n    System.out.println(JsonOut.of(Solution.twoSum(nums, target)));\n  }\n}\n"}'::jsonb, test_cases = '[{"stdin":"[[2,7,11,15],9]","expected":"[0,1]","hidden":false},{"stdin":"[[3,2,4],6]","expected":"[1,2]","hidden":false},{"stdin":"[[3,3],6]","expected":"[0,1]","hidden":true},{"stdin":"[[1,5,8,10,13],18]","expected":"[2,3]","hidden":true}]'::jsonb, companies = ARRAY['Google', 'Amazon', 'Microsoft', 'Adobe']::text[], function_name = 'twoSum' WHERE title = 'Two Sum';
UPDATE public.questions SET category = 'Strings', description = 'Given a string s containing just the characters ''('', '')'', ''{'', ''}'', ''['' and '']'', determine if the input string is valid. Reads input as a JSON array: [s]. Return true or false.', starter_code = 'function isValid(s) {
  const pairs = { '')'': ''('', '']'': ''['', ''}'': ''{'' };
  const stack = [];
  for (const ch of s) {
    if (ch === ''('' || ch === ''['' || ch === ''{'') stack.push(ch);
    else if (stack.pop() !== pairs[ch]) return false;
  }
  return stack.length === 0;
}

