('Best Time to Buy and Sell Stock', 'Given an array prices where prices[i] is the price of a stock on day i, return the maximum profit from one buy and one sell. Return 0 if no profit is possible. Reads input as a JSON array: [prices].', 'Easy', 'Arrays', 'Track the minimum price seen so far and the best profit at each step.', 'function maxProfit(prices) {
  let minPrice = Infinity, best = 0;
  for (const p of prices) {
    minPrice = Math.min(minPrice, p);
    best = Math.max(best, p - minPrice);
  }
  return best;
}

