('Maximum Subarray', 'Given an integer array nums, find the contiguous subarray with the largest sum and return its sum (Kadane''s algorithm). Reads input as a JSON array: [nums].', 'Medium', 'Arrays', 'Kadane''s algorithm: keep a running sum, resetting to the current element whenever the running sum goes negative.', 'function maxSubArray(nums) {
  let best = nums[0], cur = nums[0];
  for (let i = 1; i < nums.length; i++) {
    cur = Math.max(nums[i], cur + nums[i]);
    best = Math.max(best, cur);
  }
  return best;
}

