{\n    JsonValue v = new JsonValue(); v.type = JsonValue.Type.BOOL;\n    if (s.charAt(i) == ''t'') { v.bool = true; i += 4; } else { v.bool = false; i += 5; }\n    return v;\n  }\n  JsonValue parseNumber() {\n    JsonValue v = new JsonValue(); v.type = JsonValue.Type.NUM; int start = i;\n    while (i < s.length() && (Character.isDigit(s.charAt(i)) || \"-+.eE\".indexOf(s.charAt(i)) >= 0)) i++;\n    v.num = Double.parseDouble(s.substring(start, i)); return v;\n  }\n}\n\nclass JsonOut {\n  static String of(int v) { return String.valueOf(v); }\n  static String of(boolean v) { return v ? \"true\" : \"false\"; }\n  static String of(String v) { return \"\\\"\" + v + \"\\\"\"; }\n  static String of(int[] v) {\n    StringBuilder out = new StringBuilder(\"[\");\n    for (int k = 0; k < v.length; k++) { if (k > 0) out.append(\",\"); out.append(v[k]); }\n    return out.append(\"]\").toString();\n  }\n  static String of(int[][] v) {\n    StringBuilder out = new StringBuilder(\"[\");\n    for (int k = 0; k < v.length; k++) { if (k > 0) out.append(\",\"); out.append(of(v[k])); }\n    return out.append(\"]\").toString();\n  }\n}\n\npublic class Main {\n  public static void main(String[] args) throws IOException {\n    StringBuilder sb = new StringBuilder();\n    BufferedReader br = new BufferedReader(new InputStreamReader(System.in));\n    String line; while ((line = br.readLine()) != null) sb.append(line);\n    JsonValue input = new JsonParser(sb.toString()).parse();\n    int[] nums = input.arr.get(0).asIntArray();\n    System.out.println(JsonOut.of(Solution.maxSubArray(nums)));\n  }\n}\n"}'::jsonb, '[{"stdin":"[[-2,1,-3,4,-1,2,1,-5,4]]","expected":"6","hidden":false},{"stdin":"[[1]]","expected":"1","hidden":false},{"stdin":"[[5,4,-1,7,8]]","expected":"23","hidden":true},{"stdin":"[[-1,-2,-3]]","expected":"-1","hidden":true}]'::jsonb, ARRAY['Microsoft', 'Apple', 'LinkedIn']::text[], 'maxSubArray'),
('Coin Change', 'Given an array of coin denominations and a target amount, return the fewest number of coins needed to make up that amount, or -1 if impossible. Reads input as a JSON array: [coins, amount].', 'Medium', 'Dynamic Programming', 'Bottom-up DP: dp[a] = min coins to make amount a, building up from dp[0] = 0.', 'function coinChange(coins, amount) {
  const dp = new Array(amount + 1).fill(Infinity);
  dp[0] = 0;
  for (let a = 1; a <= amount; a++) {
    for (const c of coins) {
      if (c <= a) dp[a] = Math.min(dp[a], dp[a - c] + 1);
    }
  }
  return dp[amount] === Infinity ? -1 : dp[amount];
}

