('Binary Search', 'Given a sorted array of integers nums and an integer target, return the index of target if found, otherwise -1. Reads input as a JSON array: [nums, target].', 'Easy', 'Searching', 'Classic binary search: repeatedly halve the search range based on comparison with the midpoint.', 'function binarySearch(nums, target) {
  let lo = 0, hi = nums.length - 1;
  while (lo <= hi) {
    const mid = (lo + hi) >> 1;
    if (nums[mid] === target) return mid;
    if (nums[mid] < target) lo = mid + 1; else hi = mid - 1;
  }
  return -1;
}

