('Merge Intervals', 'Given an array of intervals where intervals[i] = [start, end], merge all overlapping intervals and return the merged list, sorted by start. Reads input as a JSON array: [intervals].', 'Medium', 'Greedy', 'Sort intervals by start time, then greedily merge any interval that overlaps with the last merged one.', 'function mergeIntervals(intervals) {
  const sorted = [...intervals].sort((a, b) => a[0] - b[0]);
  const merged = [];
  for (const [s, e] of sorted) {
    if (merged.length && s <= merged[merged.length - 1][1]) {
      merged[merged.length - 1][1] = Math.max(merged[merged.length - 1][1], e);
    } else {
      merged.push([s, e]);
    }
  }
  return merged;
}

